from __future__ import annotations

import json
import time
import uuid
import hashlib
from dataclasses import dataclass
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Dict, List, Optional

from sandbox_logger import SandboxLogger
from policies import SandboxPolicy
from sandbox_executor import SandboxExecutor

import proposal_packager
import apply_gate

SANDBOX_ROOT = Path(r"C:\AI_VAULT\tmp_agent").resolve()
LOG_PATH = SANDBOX_ROOT / "logs" / "dev.ndjson"
STATE_PATH = SANDBOX_ROOT / "sandbox_state.json"
PROPOSALS_DIR = SANDBOX_ROOT / "proposals"
RUNS_DIR = SANDBOX_ROOT / "runs"
WORK_DIR = SANDBOX_ROOT / "workspace"
STATE_DIR = SANDBOX_ROOT / "state"

REPO_ROOT = Path(r"C:\AI_VAULT\workspace\brainlab").resolve()

MAX_ITERS_DEFAULT = 1
TIMEOUT_SECONDS_DEFAULT = 60

def utc_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")

def ensure_dirs() -> None:
    for p in (SANDBOX_ROOT, PROPOSALS_DIR, RUNS_DIR, WORK_DIR, STATE_DIR, LOG_PATH.parent):
        p.mkdir(parents=True, exist_ok=True)

def load_state() -> Dict[str, Any]:
    if STATE_PATH.exists():
        try:
            return json.loads(STATE_PATH.read_text(encoding="utf-8"))
        except Exception:
            return {}
    return {}

def save_state(st: Dict[str, Any]) -> None:
    STATE_PATH.write_text(json.dumps(st, ensure_ascii=False, indent=2), encoding="utf-8")

def sha256_file(p: Path) -> str:
    h = hashlib.sha256()
    with p.open("rb") as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()

def workspace_fingerprint(include_patterns: Optional[List[str]] = None) -> Dict[str, Any]:
    include_patterns = include_patterns or ["*.py", "*.json"]
    files: List[Path] = []
    for pat in include_patterns:
        files.extend(list(WORK_DIR.rglob(pat)))
    files = sorted({p.resolve() for p in files}, key=lambda x: str(x).lower())

    entries = []
    agg = hashlib.sha256()
    for p in files:
        rel = str(p.relative_to(WORK_DIR)).replace("/", "\\")
        h = sha256_file(p)
        entries.append({"rel": rel, "sha256": h})
        agg.update(rel.encode("utf-8"))
        agg.update(h.encode("utf-8"))

    return {"count": len(entries), "entries": entries, "workspace_hash": agg.hexdigest()}

@dataclass
class LoopConfig:
    max_iters: int = MAX_ITERS_DEFAULT
    timeout_seconds: int = TIMEOUT_SECONDS_DEFAULT

class DevSandboxAgent:
    def __init__(self, cfg: LoopConfig):
        ensure_dirs()
        self.cfg = cfg
        self.run_id = f"dev_{int(time.time())}_{uuid.uuid4().hex[:8]}"
        self.logger = SandboxLogger(log_path=str(LOG_PATH), run_id=self.run_id)
        self.state = load_state()
        self.policy = SandboxPolicy.default()
        self.exec = SandboxExecutor(policy=self.policy)

    def analyze_project(self) -> Dict[str, Any]:
        info: Dict[str, Any] = {
            "ts": utc_now_iso(),
            "known_phase": self.state.get("phase", "4.5"),
            "last_run": self.state.get("last_run", None),
            "repo_root": str(REPO_ROOT),
            "workspace_root": str(WORK_DIR),
        }

        if REPO_ROOT.exists():
            res = self.exec.list_dir(str(REPO_ROOT))
            info["repo_list_ok"] = res.ok
            info["repo_list_detail"] = res.detail
            if res.ok:
                items = res.data.get("items", [])
                info["repo_top_items"] = [x.get("name") for x in items[:50]]
        else:
            info["repo_list_ok"] = False
            info["repo_list_detail"] = "REPO_ROOT_NOT_FOUND"

        scope = (self.state.get("scope_current") or "all").strip().lower()
        if scope == "contracts":
            patterns = ["*.json"]
        elif scope == "risk":
            patterns = ["*.py"]
        else:
            patterns = ["*.py", "*.json"]

        fp = workspace_fingerprint(include_patterns=patterns)
        info["workspace_hash"] = fp["workspace_hash"]
        info["workspace_file_count"] = fp["count"]
        return info

    def decide_next_step(self, analysis: Dict[str, Any]) -> Dict[str, Any]:
        risk = WORK_DIR / "risk_engine.py"
        if not risk.exists():
            return {"intent": "create_risk_engine_scaffold"}
        return {"intent": "noop"}

    def _risk_engine_scaffold(self) -> str:
        return '''# risk_engine.py (sandbox scaffold)
from __future__ import annotations

from dataclasses import dataclass
from typing import Dict, Any

@dataclass
class RiskLimits:
    max_daily_loss: float = 0.02
    max_weekly_drawdown: float = 0.06
    max_total_exposure: float = 0.70
    kill_switch: bool = False

class RiskEngine:
    def __init__(self, limits: RiskLimits):
        self.limits = limits

    def assess(self, snapshot: Dict[str, Any]) -> Dict[str, Any]:
        nlv = float(snapshot.get("nlv", 0.0) or 0.0)
        daily_pnl = float(snapshot.get("daily_pnl", 0.0) or 0.0)
        weekly_dd = float(snapshot.get("weekly_drawdown", 0.0) or 0.0)
        exposure = float(snapshot.get("total_exposure", 0.0) or 0.0)

        if self.limits.kill_switch:
            return {"verdict": "halt", "reason": "KILL_SWITCH", "limits": self.limits.__dict__}

        daily_loss_frac = 0.0
        if nlv > 0 and daily_pnl < 0:
            daily_loss_frac = abs(daily_pnl) / nlv

        violations = []
        if daily_loss_frac > self.limits.max_daily_loss:
            violations.append({"type": "MaxDailyLoss", "value": daily_loss_frac, "limit": self.limits.max_daily_loss})
        if weekly_dd > self.limits.max_weekly_drawdown:
            violations.append({"type": "MaxWeeklyDrawdown", "value": weekly_dd, "limit": self.limits.max_weekly_drawdown})
        if exposure > self.limits.max_total_exposure:
            violations.append({"type": "MaxTotalExposure", "value": exposure, "limit": self.limits.max_total_exposure})

        if violations:
            return {"verdict": "halt", "reason": "RISK_LIMIT_VIOLATION", "violations": violations}

        return {"verdict": "continue", "reason": "OK", "violations": []}
'''

    def act(self, decision: Dict[str, Any]) -> Dict[str, Any]:
        if decision.get("intent") == "create_risk_engine_scaffold":
            out_path = str(WORK_DIR / "risk_engine.py")
            wr = self.exec.write_text(out_path, self._risk_engine_scaffold())
            return {"ok": wr.ok, "detail": wr.detail, "artifact": out_path}
