    def smoke_mode(self, contract_path: str, profile: Optional[str] = None) -> Dict[str, Any]:
            """
            Runs smoke_runner.py with explicit argv:
                python smoke_runner.py --contract <path> --profile <quick|full|violations>

            Returns a dict compatible with the rest of dev_loop:
                ok/detail/returncode/stdout/stderr/cmd/parsed/contract_path/runner/repo_root
            """
            import json
            import subprocess
            from pathlib import Path

            runner = str((SANDBOX_ROOT / "smoke_runner.py").resolve())
            prof = (profile or "quick").strip().lower()
            if prof not in ("quick", "full", "violations"):
                prof = "quick"

            cmd = ["python", runner, "--contract=" + str(contract_path), "--profile=" + prof]

            try:
                proc = subprocess.run(cmd, capture_output=True, text=True)
                rc = int(proc.returncode)
                stdout = proc.stdout or ""
                stderr = proc.stderr or ""

                parsed = None
                try:
                    parsed = json.loads(stdout) if stdout.strip() else None
                except Exception:
                    parsed = None

                repo_root = None
                try:
                    if isinstance(parsed, dict):
                        repo_root = parsed.get("repo_root")
                except Exception:
                    repo_root = None
                if not repo_root:
                    try:
                        # contracts live under <repo_root>\brainlab\contracts\*.json
                        p = Path(contract_path).resolve()
                        for parent in p.parents:
                            if parent.name.lower() == "brainlab":
                                repo_root = str(parent.parent)
                                break
                        if not repo_root:
                            repo_root = str(p.parent)
                    except Exception:
                        repo_root = None

                # ok means: runner exit code == 0 AND parsed ok == True (if present)
                ok_flag = (rc == 0)
                try:
                    if isinstance(parsed, dict) and ("ok" in parsed):
                        ok_flag = ok_flag and bool(parsed.get("ok"))
                except Exception:
                    pass

                out = {
                    "ok": bool(ok_flag),
                    "detail": "OK" if ok_flag else "NONZERO_EXIT",
                    "returncode": rc,
                    "stdout": stdout,
                    "stderr": stderr,
                    "cmd": cmd,
                    "parsed": parsed,
                    "contract_path": str(contract_path),
                    "runner": runner,
                    "repo_root": str(repo_root) if repo_root else None,
                }
                return out
            except Exception as e:
                return {
                    "ok": False,
                    "detail": "EXCEPTION",
                    "returncode": 1,
                    "stdout": "",
                    "stderr": repr(e),
                    "cmd": cmd,
                    "parsed": None,
                    "contract_path": str(contract_path),
                    "runner": runner,
                    "repo_root": None,
                }
    def apply_mode(self, bundle_path: str, approve: str, dest_dir: Optional[str] = None, post_smoke: Optional[str] = None, post_smoke_mode: Optional[str] = None, post_smoke_profile: Optional[str] = None) -> Dict[str, Any]:
        self.logger.emit("run_start", {"mode": "apply", "bundle_path": bundle_path})
        out = {"ok": False}  # init out to avoid UnboundLocalError
        # --- pre-apply tools snapshot (per-run) ---
        preapply_snapshot_dir = None
        try:
            import time, hashlib

            st = (SANDBOX_ROOT / "state")
            st.mkdir(parents=True, exist_ok=True)

            ts = time.strftime("%Y%m%d_%H%M%S")
            snap = st / f"tools_snapshot_PREAPPLY_{self.run_id}_{ts}"
            snap.mkdir(parents=True, exist_ok=True)

            # copy *.py tools from SANDBOX_ROOT to snapshot
            py_files = list(SANDBOX_ROOT.glob("*.py"))
            for p in py_files:
                try:
                    (snap / p.name).write_bytes(p.read_bytes())
                except Exception:
                    pass

            # hashes file: "<sha256>  <absolute_path_under_root>"
            lines = []
            for sp in snap.glob("*.py"):
                try:
                    h = hashlib.sha256(sp.read_bytes()).hexdigest().upper()
                    dst_abs = str((SANDBOX_ROOT / sp.name).resolve())
                    lines.append(f"{h}  {dst_abs}")
                except Exception:
                    pass
            (snap / "_hashes.sha256.txt").write_text("\n".join(lines), encoding="utf-8")
            preapply_snapshot_dir = str(snap.resolve())
            try:
                self.logger.emit("preapply_tools_snapshot", {"snapshot_dir": preapply_snapshot_dir, "count": len(lines)})
            except Exception:
                pass
        except Exception:
            preapply_snapshot_dir = None

        try:
            import time, hashlib

            st = (SANDBOX_ROOT / "state")
            st.mkdir(parents=True, exist_ok=True)

            ts = time.strftime("%Y%m%d_%H%M%S")
            snap = st / f"tools_snapshot_PREAPPLY_{self.run_id}_{ts}"
