                    (snap / p.name).write_bytes(p.read_bytes())
                except Exception:
                    pass

            # hashes file: "<sha256>  <absolute_path_under_root>"
            lines = []
            for sp in snap.glob("*.py"):
                try:
                    h = hashlib.sha256(sp.read_bytes()).hexdigest().upper()
                    dst_abs = str((SANDBOX_ROOT / sp.name).resolve())
                    lines.append(f"{h}  {dst_abs}")
                except Exception:
                    pass
            (snap / "_hashes.sha256.txt").write_text("\n".join(lines), encoding="utf-8")
            preapply_snapshot_dir = str(snap.resolve())
            try:
                self.logger.emit("preapply_tools_snapshot", {"snapshot_dir": preapply_snapshot_dir, "count": len(lines)})
            except Exception:
                pass
        except Exception:
            preapply_snapshot_dir = None

        out = apply_gate.apply_bundle(bundle_path=bundle_path, dest_dir=dest_dir, approve_token=approve)
        self.logger.emit("apply_result", out)
        # --- post-smoke gating (optional) ---
        post_mode = (post_smoke_mode or "strict").strip().lower()
        if post_mode not in ("strict", "warn", "off"):
            post_mode = "strict"

        if (post_mode != "off") and post_smoke and bool(out.get("ok", False)):
            smoke_out = self.smoke_mode(contract_path=post_smoke, profile=post_smoke_profile or "full") or {}

            # audit log (best-effort)
            try:
                self.logger.emit("post_smoke", {"post_smoke": post_smoke, "smoke": smoke_out})
            except Exception:
                pass

            ok = bool(smoke_out.get("ok", False))
            rc = smoke_out.get("returncode", 0)
            try:
                rc = int(rc)
            except Exception:
                rc = 999

            parsed = smoke_out.get("parsed") or {}
            results = parsed.get("results") or []
            has_halt = False
            # normalize: any HALT means post-smoke not OK
            if has_halt:
                ok = False
            # propagate into smoke_out for clearer logs/rollback context
            try:
                smoke_out["has_halt"] = bool(has_halt)
                smoke_out["ok"] = bool(ok)
            except Exception:
                pass
            try:
                for r in results:
                    assess = (r or {}).get("assess") or {}
                    if str(assess.get("verdict", "")).lower() == "halt":
                        has_halt = True
                        # normalize: any HALT means post-smoke not OK
                        if has_halt:
                            ok = False
                        # propagate into smoke_out for clearer logs/rollback context
                        try:
                            smoke_out["has_halt"] = bool(has_halt)
                            smoke_out["ok"] = bool(ok)
                        except Exception:
                            pass
                        break
            except Exception:
                has_halt = True
                # normalize: any HALT means post-smoke not OK
                if has_halt:
                    ok = False
                # propagate into smoke_out for clearer logs/rollback context
                try:
                    smoke_out["has_halt"] = bool(has_halt)
                    smoke_out["ok"] = bool(ok)
                except Exception:
                    pass

            failed = (not ok) or (rc != 0) or has_halt
            if failed and post_mode == "warn":
                try:
                    smoke_summary = {}
                    try:
                        p = smoke_out.get("parsed") if isinstance(smoke_out, dict) else None
                        if isinstance(p, dict):
                            vio_types = []
                            for hr in (p.get("halt_reasons") or []):
                                for v in (hr.get("violations") or []):
                                    t = v.get("type")
                                    if t and t not in vio_types:
                                        vio_types.append(t)
                            smoke_summary = {
                                "profile": p.get("profile"),
                                "rc": smoke_out.get("returncode"),
                                "has_halt": bool(p.get("has_halt")),
                                "violation_types": vio_types
                            }
                    except Exception:
                        smoke_summary = {}
                    self.logger.emit("post_smoke_warn", {"smoke_summary": smoke_summary,"post_smoke": post_smoke, "ok": ok, "rc": rc, "has_halt": has_halt})
                except Exception:
                    pass
            if failed and post_mode == "strict":
                # --- rollback best-effort ---
                revert_bundle = None
                try:
                    if isinstance(out, dict):
                        for k in ("revert_bundle","rollback_bundle","revert","rollback","bundle_revert","bundle_rollback"):
                            v = out.get(k)
                            if isinstance(v, str) and v.strip():
                                revert_bundle = v.strip()
                                break
                except Exception:
                    revert_bundle = None

                if revert_bundle:
                    try:
                        self.logger.emit("rollback_apply_bundle", {"revert_bundle": revert_bundle, "reason": "post_smoke_failed"})
                    except Exception:
                        pass
                    try:
                        apply_gate.apply_bundle(bundle_path=revert_bundle, dest_dir=dest_dir, approve_token=approve)
                    except Exception:
                        pass
                else:
                    # --- rollback repo using apply receipt (best-effort) ---
                    try:
                        import shutil

                        # repo_root from smoke parsed output if available; fallback to C:\AI_VAULT\workspace\brainlab
                        repo_root = None
                        try:
                            repo_root = (smoke_out.get("repo_root") or (smoke_out.get("parsed") or {}).get("repo_root"))
                        except Exception:
                            repo_root = None
                        if not repo_root:
                            # Prefer dest_dir (apply target), else derive from post_smoke path
                            try:
                                if dest_dir:
                                    repo_root = str(Path(dest_dir).resolve())
                                elif post_smoke:
                                    # contracts live under <repo_root>\brainlab\contracts\*.json
                                    psm = Path(post_smoke).resolve()
                                    # walk up to find repo root by locating "brainlab" dir
                                    repo_root = None
                                    for parent in [psm.parent, psm.parent.parent, psm.parent.parent.parent, psm.parent.parent.parent.parent]:
                                        if parent.name.lower() == "brainlab":
                                            repo_root = str(parent.parent)
                                            break
                                    if not repo_root:
                                        repo_root = str(psm.parent.parent.parent)  # best-effort
                            except Exception:
                                repo_root = None
                        repo_root_p = Path(repo_root).resolve()
                        restored_count = 0
                        deleted_count = 0
                        restored_paths = []
                        deleted_paths = []

                        # 1) restore modified files from backups
                        backups = out.get("backups") if isinstance(out, dict) else None
                        if isinstance(backups, list):
                            for b in backups:
                                try:
                                    dest = Path(b.get("dest","")).resolve()
                                    bak = Path(b.get("bak","")).resolve()
                                    if repo_root_p not in dest.parents and dest != repo_root_p:
                                        continue
                                    if bak.exists():
                                        shutil.copy2(str(bak), str(dest))
                                        restored_count += 1
                                        if len(restored_paths) < 10:
                                            restored_paths.append(str(dest))
                                except Exception:
                                    pass

                        # 2) delete newly created files that have no backup
                        applied = out.get("applied") if isinstance(out, dict) else None
                        if isinstance(applied, list):
                            backed_dests = set()
                            if isinstance(backups, list):
                                for b in backups:
                                    try:
                                        backed_dests.add(str(Path(b.get("dest","")).resolve()))
                                    except Exception:
                                        pass

                            for a in applied:
                                try:
                                    if (a.get("kind") != "new_file"):
                                        continue
                                    dest = Path(a.get("dest","")).resolve()
                                    if repo_root_p not in dest.parents and dest != repo_root_p:
                                        continue
                                    if str(dest) in backed_dests:
                                        continue
                                    if dest.exists() and dest.is_file():
                                        dest.unlink()
                                        deleted_count += 1
                                        if len(deleted_paths) < 10:
                                            deleted_paths.append(str(dest))
                                except Exception:
                                    pass

                        try:
                            self.logger.emit("rollback_repo_applied", {
                                "reason": "post_smoke_failed",
                                "repo_root": str(repo_root_p),
                                "restored": restored_count,
                                "deleted": deleted_count,
                                "restored_paths": restored_paths,
                                "deleted_paths": deleted_paths
                            })
                        except Exception:
                            pass
                    except Exception:
                        pass

                    # restore tools snapshot (baseline-with-gating)
                    snapshot_dir = None
                    try:
                        st = SANDBOX_ROOT / "state"
                        if st.exists():
                            cands = sorted([p for p in st.glob("tools_snapshot*") if p.is_dir()], key=lambda p: p.stat().st_mtime, reverse=True)
                            for p in cands:
                                if "BASELINE_WITH_GATING" in p.name:
                                    snapshot_dir = str(p)
                                    break
                            if not snapshot_dir:
                                for p in cands:
                                    if "BASELINE" in p.name:
                                        snapshot_dir = str(p)
                                        break
                            if not snapshot_dir and cands:
                                snapshot_dir = str(cands[0])
                    except Exception:
                        snapshot_dir = None

                    if snapshot_dir:
                        try:
                            # force preapply snapshot (final override)
                            if preapply_snapshot_dir:
                                snapshot_dir = preapply_snapshot_dir
                            self.logger.emit("rollback_restore_tools_snapshot", {"snapshot_dir": snapshot_dir, "reason": "post_smoke_failed"})
                        except Exception:
                            pass
                        try:
                            import subprocess
                            # Prefer PowerShell 7 if available, else Windows PowerShell
                            ps_exe = "pwsh.exe"
                            try:
                                import shutil
                                if not shutil.which(ps_exe):
                                    ps_exe = "powershell.exe"
                            except Exception:
                                ps_exe = "powershell.exe"

                            cmd = [
                                ps_exe,
                                "-ExecutionPolicy", "Bypass",
                                "-File", str(SANDBOX_ROOT / "restore_tools.ps1"),
                                "-SnapshotDir", snapshot_dir,
                                "-NoSmoke"
                            ]
                            proc = subprocess.run(cmd, capture_output=True, text=True, env=env)
                            try:
                                self.logger.emit("rollback_restore_tools_snapshot_result", {"snapshot_dir": snapshot_dir, "rc": proc.returncode, "stdout": (proc.stdout or "")[-2000:], "stderr": (proc.stderr or "")[-2000:]})
                            except Exception:
                                pass
                        except Exception:
                            pass

                raise RuntimeError(f"POST_SMOKE_FAILED: ok={ok} rc={rc} has_halt={has_halt} smoke={smoke_out}")

        self.state["last_apply"] = {"ts": utc_now_iso(), "bundle_path": bundle_path, "ok": out.get("ok"), "proposal_id": out.get("proposal_id"), "run_id": out.get("run_id"), "preapply_snapshot_dir": preapply_snapshot_dir, "post_smoke": post_smoke}
        try:
            self.state["last_apply"].update({"post_smoke_mode": post_smoke_mode, "post_smoke_profile": post_smoke_profile})
        except Exception:
            pass
        save_state(self.state)

        # --- cleanup PREAPPLY snapshots (best-effort) ---
        try:
            st = (SANDBOX_ROOT / "state")
            if st.exists():
                snaps = sorted([p for p in st.glob("tools_snapshot_PREAPPLY_*") if p.is_dir()],
                               key=lambda p: p.stat().st_mtime, reverse=True)
                keep = 30
                for p in snaps[keep:]:
                    try:
                        # remove dir tree
                        for child in p.rglob("*"):
                            try:
                                if child.is_file():
                                    child.unlink()
                            except Exception:
                                pass
                        for child in sorted([d for d in p.rglob("*") if d.is_dir()], key=lambda d: len(str(d)), reverse=True):
                            try:
                                child.rmdir()
                            except Exception:
                                pass
                        p.rmdir()
                    except Exception:
                        pass
        except Exception:
            pass
        return out

def parse_args(argv: List[str]) -> Dict[str, Any]:
    args: Dict[str, Any] = {"mode": "run", "bundle": None, "approve": None, "dest": None, "scope": "all", "contract": None, "post_smoke": None, "post_smoke_mode": "strict", "post_smoke_profile": "full"}
    for a in argv[1:]:
        if a.startswith("--mode="):
            args["mode"] = a.split("=", 1)[1].strip()
        elif a.startswith("--bundle="):
            args["bundle"] = a.split("=", 1)[1].strip()
        elif a.startswith("--approve="):
            args["approve"] = a.split("=", 1)[1].strip()
        elif a.startswith("--dest="):
            args["dest"] = a.split("=", 1)[1].strip()
        elif a.startswith("--scope="):
            args["scope"] = a.split("=", 1)[1].strip()
        elif a.startswith("--contract="):
            args["contract"] = a.split("=", 1)[1].strip()
        elif a.startswith("--post_smoke="):
            args["post_smoke"] = a.split("=", 1)[1].strip()
        elif a.startswith("--post_smoke_mode="):
            args["post_smoke_mode"] = a.split("=", 1)[1].strip()
        elif a.startswith("--post_smoke_profile="):
            args["post_smoke_profile"] = a.split("=", 1)[1].strip()
    return args
def main(argv: List[str]) -> int:
    import json

    agent = DevSandboxAgent(LoopConfig())

    try:
        a = parse_args(argv)
        mode = a.get("mode") or "run"

        if mode == "run":
            out = agent.run_mode()

        elif mode == "package":
            agent.state["scope_current"] = a.get("scope") or "all"
            save_state(agent.state)
            out = agent.package_mode()

        elif mode == "apply":
            if not a.get("bundle") or not a.get("approve"):
                raise SystemExit("apply mode requires --bundle=<path> and --approve=APPLY_<proposal_id>")
            out = agent.apply_mode(
                bundle_path=a["bundle"],
                approve=a["approve"],
                dest_dir=a.get("dest"),
                post_smoke=a.get("post_smoke"), post_smoke_mode=a.get("post_smoke_mode")
            , post_smoke_profile=a.get("post_smoke_profile"))

        elif mode == "smoke":
            if not a.get("contract"):
                raise SystemExit("smoke mode requires --contract=<path_to_contract_json>")
            out = agent.smoke_mode(contract_path=a["contract"])

        else:
            raise SystemExit(f"Unknown mode: {mode}")

        if out is None:
            out = {"ok": True, "detail": "OK"}

        # Print JSON result
        try:
            print(json.dumps(out, ensure_ascii=False, indent=2))
        except Exception:
            print(str(out))

        ok = True
        if isinstance(out, dict):
            ok = bool(out.get("ok", True))
        return 0 if ok else 2

    except SystemExit as e:
        # Normalize to JSON
        code = e.code if isinstance(e.code, int) else 2
        err = {"ok": False, "error_type": "SystemExit", "message": str(e)}
        try:
            err["last_apply"] = (agent.state or {}).get("last_apply")
        except Exception:
            pass
        print(json.dumps(err, ensure_ascii=False, indent=2))
        return code

    except Exception as e:
        err = {"ok": False, "error_type": e.__class__.__name__, "message": str(e)}
        try:
            err["last_apply"] = (agent.state or {}).get("last_apply")
        except Exception:
            pass
        print(json.dumps(err, ensure_ascii=False, indent=2))
        return 2

if __name__ == "__main__":
    import sys
    raise SystemExit(main(sys.argv))

import json
import os
import sys
from pathlib import Path
from datetime import datetime, timezone
import io
import contextlib


def utc_iso() -> str:
    return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")


def _derive_repo_root(contract_path: str) -> str:
    """
    Best-effort: contracts live under <repo_root>\\brainlab\\contracts\\*.json
    If we can find a parent named 'brainlab', repo_root = parent.parent.
    Else fallback to the contract's parent directory.
    """
    try:
        p = Path(contract_path).resolve()
        for parent in p.parents:
            if parent.name.lower() == "brainlab":
                return str(parent.parent)
        return str(p.parent)
    except Exception:
        return ""


def _get_contract_from_argv_env(argv) -> str:
    # argv supports:
    #   --contract=PATH
    #   --contract PATH
    #   positional PATH
    for i, a in enumerate(argv):
        if a.startswith("--contract="):
            return a.split("=", 1)[1].strip()
        if a == "--contract" and i + 1 < len(argv):
            return (argv[i + 1] or "").strip()

    # positional
    if argv and not argv[0].startswith("--"):
        return (argv[0] or "").strip()

    # explicit env fallbacks (known/common)
    for k in (
        "CONTRACT_PATH", "SMOKE_CONTRACT", "SMOKE_CONTRACT_PATH",
        "CONTRACT", "contract", "contract_path",
        "POST_SMOKE", "POST_SMOKE_CONTRACT", "POST_SMOKE_CONTRACT_PATH",
        "POST_SMOKE_PATH", "post_smoke", "post_smoke_path",
    ):
        v = os.environ.get(k)
        if v and v.strip():
            return v.strip()

    # last resort: scan env for anything that looks like a contract json path
    # Prefer keys containing CONTRACT/SMOKE; prefer existing paths; prefer *.json
    candidates = []
    for k, v in os.environ.items():
        if not v or not isinstance(v, str):
            continue
        vv = v.strip()
        if not vv:
            continue
        lk = k.lower()
        if ("contract" not in lk) and ("smoke" not in lk):
            continue
        # quick plausibility
        if (".json" in vv.lower()) or (":\\" in vv) or ("/" in vv):
            candidates.append((k, vv))

    def score(item):
        k, vv = item
        lk = k.lower()
        s = 0
        if "contract" in lk: s += 5
        if "smoke" in lk: s += 3
        if "post_smoke" in lk: s += 4
        if vv.lower().endswith(".json"): s += 5
        try:
            if Path(vv).exists(): s += 10
        except Exception:
            pass
        return s

    candidates.sort(key=score, reverse=True)
    for k, vv in candidates:
        try:
            if Path(vv).exists() or vv.lower().endswith(".json"):
                return vv
        except Exception:
            continue

    return ""
def _get_profile_from_argv_env(argv) -> str:
    # --profile=quick|full|violations
    for a in argv:
        if a.startswith("--profile="):
            return a.split("=", 1)[1].strip().lower()
    # env fallback
    v = os.environ.get("SMOKE_PROFILE") or os.environ.get("smoke_profile")
    if v:
        return v.strip().lower()
    return "quick"
def main(argv=None) -> int:
    argv = list(argv) if argv is not None else sys.argv[1:]
    contract = _get_contract_from_argv_env(argv)

    if not contract:
        out = {"ok": False, "error": "MISSING_CONTRACT_PATH"}
        sys.stdout.write(json.dumps(out, ensure_ascii=False, indent=2) + "\n")
        return 1

    # Import RiskEngine with stdout suppressed to avoid extra prints corrupting JSON output
    try:
        with contextlib.redirect_stdout(io.StringIO()):
            from smoke_risk_engine import RiskEngine
    except Exception as e:
        out = {"ok": False, "error": "IMPORT_FAILED", "detail": repr(e)}
        sys.stdout.write(json.dumps(out, ensure_ascii=False, indent=2) + "\n")
        return 1

    try:
        re = RiskEngine.from_contract_path(contract)
    except Exception as e:
        out = {"ok": False, "error": "LOAD_CONTRACT_FAILED", "contract_path": contract, "detail": repr(e)}
        sys.stdout.write(json.dumps(out, ensure_ascii=False, indent=2) + "\n")
        return 1
    profile = _get_profile_from_argv_env(argv)
    if profile not in ("quick", "full", "violations"):
        profile = "quick"

    # Profiles:
    # - quick: only a safe "ok" snapshot
    # - full: ok + violation cases (stress)
    # - violations: only the violation cases
    tests_ok = [
        {"name": "ok", "snapshot": {"nlv": 1000.0, "daily_pnl": -5.0, "weekly_drawdown": 0.01, "total_exposure": 0.35}},
    ]
    tests_viol = [
        {"name": "daily_loss_violation", "snapshot": {"nlv": 1000.0, "daily_pnl": -25.0, "weekly_drawdown": 0.01, "total_exposure": 0.35}},
        {"name": "weekly_dd_violation", "snapshot": {"nlv": 1000.0, "daily_pnl": 0.0, "weekly_drawdown": 0.10, "total_exposure": 0.35}},
        {"name": "exposure_violation", "snapshot": {"nlv": 1000.0, "daily_pnl": 0.0, "weekly_drawdown": 0.01, "total_exposure": 0.95}},
    ]

    if profile == "quick":
        tests = tests_ok
    elif profile == "violations":
        tests = tests_viol
    else:
        tests = tests_ok + tests_viol
    results = [{"name": t["name"], "assess": re.assess(t["snapshot"])} for t in tests]

    has_halt = False
    halt_reasons = []
    for r in results:
        a = r.get("assess") or {}
        if a.get("verdict") == "halt":
            has_halt = True
            halt_reasons.append({
                "name": r.get("name"),
                "reason": a.get("reason"),
                "violations": a.get("violations") or []
            })

    limits = {}
    try:
        limits = getattr(re, "limits").__dict__ if getattr(re, "limits", None) is not None else {}
    except Exception:
        limits = {}

    out = {
        "profile": profile,
        "ts": utc_iso(),
        "contract_path": contract,
        "repo_root": _derive_repo_root(contract),
        "limits": limits,
        "results": results,
        "has_halt": bool(has_halt),
        "halt_reasons": halt_reasons,
        # ok means "policy passed"
        "ok": (not has_halt),
    }

    sys.stdout.write(json.dumps(out, ensure_ascii=False, indent=2) + "\n")
    return 2 if has_halt else 0


if __name__ == "__main__":
    raise SystemExit(main())
